285→export const uploadCommand = buildCommand({
286→	loader: async () => ({ default: runUpload }),
287→	parameters: {
288→		positional: {
289→			kind: "array",
290→			parameter: {
291→				brief: "Session ID or path to a session .jsonl file",
292→				parse: String,
293→				placeholder: "session",
294→			},
295→		},
296→		flags: {
297→			tag: {
298→				kind: "enum",
299→				values: [...SESSION_TAGS],
300→				brief: "Session tag/category",
301→				optional: true,
302→			},
303→			endpoint: {
304→				kind: "parsed",
305→				parse: String,
306→				brief: "Override the upload endpoint URL",
307→				default: DEFAULT_ENDPOINT,
308→			},
309→			classify: {
310→				kind: "boolean",
311→				brief: "Auto-classify session tag using Claude CLI",
312→				default: false,
313→			},
314→			dryRun: {
315→				kind: "boolean",
316→				brief: "Preview what would be uploaded without sending",
317→				default: false,
318→			},
319→			org: {
320→				kind: "parsed",
321→				parse: String,
322→				brief: "Override the organization ID to upload to",
323→				optional: true,
324→			},
325→		},
326→		aliases: {
327→			t: "tag",
328→			c: "classify",
329→			n: "dryRun",
330→			o: "org",
331→		},
332→	},
333→	docs: {
334→		brief:
335→			"Upload Claude Code session transcripts. No args = interactive project picker.",
336→	},
337→});
