161→async function runSingleUpload(
162→	flags: UploadFlags,
163→	session: string,
164→): Promise<void> {
165→	const write = (msg: string) => {
166→		process.stdout.write(`${msg}\n`);
167→	};
168→	const writeError = (msg: string) => {
169→		process.stderr.write(`${msg}\n`);
170→	};
171→
172→	const credentials = loadCredentials();
173→	if (!credentials && !flags.dryRun) {
174→		writeError("Error: Not authenticated. Run `rudel login` first.");
175→		process.exitCode = 1;
176→		return;
177→	}
178→
179→	write(`Resolving session: ${session}`);
180→	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
181→	try {
182→		sessionInfo = await resolveSession(session);
183→	} catch (error) {
184→		writeError(
185→			`Error: ${error instanceof Error ? error.message : String(error)}`,
186→		);
187→		process.exitCode = 1;
188→		return;
189→	}
190→	write(`Found session at: ${sessionInfo.transcriptPath}`);
191→
192→	write("Reading transcript...");
193→	let content: string;
194→	try {
195→		content = await readTranscript(sessionInfo.transcriptPath);
196→	} catch (error) {
197→		writeError(
198→			`Error reading transcript: ${error instanceof Error ? error.message : String(error)}`,
199→		);
200→		process.exitCode = 1;
201→		return;
202→	}
203→	write(`Transcript: ${content.length} bytes`);
204→
205→	const agentIds = extractAgentIds(content);
206→	let subagents: SubagentFile[] = [];
207→	if (agentIds.length > 0) {
208→		write(`Found ${agentIds.length} subagent(s): ${agentIds.join(", ")}`);
209→		subagents = await readSubagentFiles(
210→			sessionInfo.sessionDir,
211→			agentIds,
212→			sessionInfo.sessionId,
213→		);
214→		write(
215→			`Read ${subagents.length} subagent file(s): ${subagents.reduce((sum, s) => sum + s.content.length, 0)} bytes total`,
216→		);
217→	}
218→
219→	const gitInfo = await getGitInfo(sessionInfo.projectPath);
220→	if (gitInfo.repository) write(`Repository: ${gitInfo.repository}`);
221→	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);
222→
223→	let tag = flags.tag;
224→	if (!tag && flags.classify) {
225→		write("Classifying session...");
226→		tag = (await classifySession(content)) ?? undefined;
227→		if (tag) write(`Classified as: ${tag}`);
228→	}
229→
230→	const organizationId =
231→		flags.org ?? (await getProjectOrgId(sessionInfo.projectPath));
232→	if (organizationId) write(`Organization: ${organizationId}`);
233→
234→	const request: IngestRequest = {
235→		sessionId: sessionInfo.sessionId,
236→		projectPath: sessionInfo.projectPath,
237→		repository: gitInfo.repository,
238→		gitBranch: gitInfo.branch,
239→		gitSha: gitInfo.sha,
240→		tag,
241→		content,
242→		subagents: subagents.length > 0 ? subagents : undefined,
243→		organizationId,
244→	};
245→
246→	if (flags.dryRun) {
247→		const preview = {
248→			...request,
249→			content: `[${request.content.length} bytes]`,
250→			subagents: request.subagents?.map((s) => ({
251→				...s,
252→				content: `[${s.content.length} bytes]`,
253→			})),
254→		};
255→		write("Dry run - would upload:");
256→		write(JSON.stringify(preview, null, 2));
257→		return;
258→	}
259→
260→	write("Uploading...");
261→	const result = await uploadSession(request, {
262→		endpoint: flags.endpoint,
263→		// biome-ignore lint/style/noNonNullAssertion: validated above with early return
264→		token: credentials!.token,
265→	});
266→
267→	if (result.success) {
268→		write("Upload successful!");
269→	} else {
270→		writeError(`Upload failed: ${result.error}`);
271→		process.exitCode = 1;
272→	}
273→}
274→
275→async function runUpload(
276→	flags: UploadFlags,
277→	...sessions: string[]
278→): Promise<void> {
279→	if (sessions.length === 0) {
280→		return runInteractiveUpload(flags);
281→	}
282→	return runSingleUpload(flags, sessions[0] as string);
283→}
