 14→async function promptChoice(question: string, max: number): Promise<number> {
 15→	const rl = createInterface({ input: process.stdin, output: process.stdout });
 16→	return new Promise((resolve) => {
 17→		rl.question(question, (answer) => {
 18→			rl.close();
 19→			const num = Number.parseInt(answer.trim(), 10);
 20→			if (Number.isNaN(num) || num < 1 || num > max) {
 21→				resolve(1);
 22→			} else {
 23→				resolve(num);
 24→			}
 25→		});
 26→	});
 27→}
 28→
 29→async function promptYesNo(question: string): Promise<boolean> {
 30→	const rl = createInterface({ input: process.stdin, output: process.stdout });
 31→	return new Promise((resolve) => {
 32→		rl.question(question, (answer) => {
 33→			rl.close();
 34→			resolve(answer.trim().toLowerCase() === "y");
 35→		});
 36→	});
 37→}
