 1→import { readdir } from "node:fs/promises";
 2→import { homedir } from "node:os";
 3→import { decodeProjectPath, SESSIONS_BASE_DIR } from "./session-resolver.js";
 4→
 5→export interface ScannedProject {
 6→	encodedDir: string;
 7→	decodedPath: string;
 8→	displayPath: string;
 9→	sessionDir: string;
10→	sessionCount: number;
11→	sessionIds: string[];
12→}
13→
14→export interface GroupedProjects {
15→	current?: ScannedProject;
16→	subfolders: ScannedProject[];
17→	others: ScannedProject[];
18→}
19→
20→export async function scanProjects(): Promise<ScannedProject[]> {
21→	let projectDirs: string[];
22→	try {
23→		projectDirs = await readdir(SESSIONS_BASE_DIR);
24→	} catch {
25→		return [];
26→	}
27→
28→	const home = homedir();
29→	const projects: ScannedProject[] = [];
30→
31→	for (const dir of projectDirs) {
32→		const sessionDir = `${SESSIONS_BASE_DIR}/${dir}`;
33→		let files: string[];
34→		try {
35→			files = await readdir(sessionDir);
36→		} catch {
37→			continue;
38→		}
39→
40→		const sessionIds = files
41→			.filter((f) => f.endsWith(".jsonl") && !f.startsWith("agent-"))
42→			.map((f) => f.replace(/\.jsonl$/, ""));
43→
44→		if (sessionIds.length === 0) continue;
45→
46→		const decodedPath = await decodeProjectPath(dir);
47→		const displayPath = decodedPath.startsWith(home)
48→			? `~${decodedPath.slice(home.length)}`
49→			: decodedPath;
50→
51→		projects.push({
52→			encodedDir: dir,
53→			decodedPath,
54→			displayPath,
55→			sessionDir,
56→			sessionCount: sessionIds.length,
57→			sessionIds,
58→		});
59→	}
60→
61→	return projects;
62→}
63→
64→export function groupProjectsForCwd(
65→	projects: ScannedProject[],
66→	cwd: string,
67→): GroupedProjects {
68→	const current = projects.find((p) => p.decodedPath === cwd);
69→	const subfolders = projects.filter(
70→		(p) =>
71→			p !== current &&
72→			current !== undefined &&
73→			p.decodedPath.startsWith(`${current.decodedPath}/`),
74→	);
75→	const others = projects.filter(
76→		(p) => p !== current && !subfolders.includes(p),
77→	);
78→
79→	subfolders.sort((a, b) => a.decodedPath.localeCompare(b.decodedPath));
80→	others.sort((a, b) => a.displayPath.localeCompare(b.displayPath));
81→
82→	return { current, subfolders, others };
83→}
