  4→import type { ScannedProject } from "./project-scanner.js";
  5→import { readSubagentFiles } from "./subagent-reader.js";
  6→import { extractAgentIds, readTranscript } from "./transcript-reader.js";
  7→import type { IngestRequest, SessionTag, SubagentFile } from "./types.js";
  8→import { type UploadConfig, uploadSession } from "./uploader.js";
