 10→export interface BatchOptions {
 11→	tag?: SessionTag;
 12→	classify: boolean;
 13→	dryRun: boolean;
 14→	org?: string;
 15→	uploadConfig: UploadConfig;
 16→}
 17→
 18→export interface BatchResult {
 19→	succeeded: number;
 20→	failed: number;
 21→	errors: Array<{ sessionId: string; project: string; error: string }>;
 22→}
 23→
 24→export async function uploadOneSession(
 25→	sessionDir: string,
 26→	sessionId: string,
 27→	projectPath: string,
 28→	options: BatchOptions,
 29→): Promise<{ success: boolean; error?: string }> {
 30→	const transcriptPath = `${sessionDir}/${sessionId}.jsonl`;
 31→
 32→	let content: string;
 33→	try {
 34→		content = await readTranscript(transcriptPath);
 35→	} catch (error) {
 36→		return {
 37→			success: false,
 38→			error: `Failed to read: ${error instanceof Error ? error.message : String(error)}`,
 39→		};
 40→	}
 41→
 42→	const agentIds = extractAgentIds(content);
 43→	let subagents: SubagentFile[] = [];
 44→	if (agentIds.length > 0) {
 45→		subagents = await readSubagentFiles(sessionDir, agentIds, sessionId);
 46→	}
 47→
 48→	const gitInfo = await getGitInfo(projectPath);
 49→
 50→	let tag = options.tag;
 51→	if (!tag && options.classify) {
 52→		tag = (await classifySession(content)) ?? undefined;
 53→	}
 54→
 55→	const organizationId = options.org ?? (await getProjectOrgId(projectPath));
 56→
 57→	const request: IngestRequest = {
 58→		sessionId,
 59→		projectPath,
 60→		repository: gitInfo.repository,
 61→		gitBranch: gitInfo.branch,
 62→		gitSha: gitInfo.sha,
 63→		tag,
 64→		content,
 65→		subagents: subagents.length > 0 ? subagents : undefined,
 66→		organizationId,
 67→	};
 68→
 69→	if (options.dryRun) {
 70→		return { success: true };
 71→	}
 72→
 73→	const result = await uploadSession(request, options.uploadConfig);
 74→	if (result.success) {
 75→		return { success: true };
 76→	}
 77→	return { success: false, error: result.error };
 78→}
 79→
 80→export async function batchUpload(
 81→	projects: ScannedProject[],
 82→	options: BatchOptions,
 83→	onProgress: (current: number, total: number, sessionId: string) => void,
 84→): Promise<BatchResult> {
 85→	const totalSessions = projects.reduce(
 86→		(sum, p) => sum + p.sessionIds.length,
 87→		0,
 88→	);
 89→	let completed = 0;
 90→	const result: BatchResult = { succeeded: 0, failed: 0, errors: [] };
 91→
 92→	for (const project of projects) {
 93→		for (const sessionId of project.sessionIds) {
 94→			completed++;
 95→			onProgress(completed, totalSessions, sessionId);
 96→
 97→			const outcome = await uploadOneSession(
 98→				project.sessionDir,
 99→				sessionId,
100→				project.decodedPath,
101→				options,
102→			);
103→
104→			if (outcome.success) {
105→				result.succeeded++;
106→			} else {
107→				result.failed++;
108→				result.errors.push({
109→					sessionId,
110→					project: project.displayPath,
111→					error: outcome.error ?? "Unknown error",
112→				});
113→			}
114→		}
115→	}
116→
117→	return result;
118→}
