  2→import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
  3→import { dirname, join, resolve } from "node:path";
  4→
  5→const HOOK_COMMAND = "rudel hooks claude session-end";
  6→
  7→interface HookEntry {
  8→	type: string;
  9→	command: string;
 10→	async?: boolean;
 11→}
 12→
 13→interface HookMatcher {
 14→	matcher: string;
 15→	hooks: HookEntry[];
 16→}
 17→
 18→interface ClaudeSettings {
 19→	hooks?: {
 20→		SessionEnd?: HookMatcher[];
 21→		[key: string]: unknown;
 22→	};
 23→	[key: string]: unknown;
 24→}
 25→
 26→function findClaudeDir(): string {
 27→	let dir = resolve(process.cwd());
 28→
 29→	// Walk up looking for an existing .claude directory
 30→	while (dir !== dirname(dir)) {
 31→		const candidate = join(dir, ".claude");
 32→		if (existsSync(candidate)) {
 33→			return candidate;
 34→		}
 35→		dir = dirname(dir);
 36→	}
 37→
 38→	// Fall back to git repo root
 39→	try {
 40→		const gitRoot = execSync("git rev-parse --show-toplevel", {
 41→			encoding: "utf-8",
 42→			stdio: ["pipe", "pipe", "pipe"],
 43→		}).trim();
 44→		return join(gitRoot, ".claude");
 45→	} catch {
 46→		// Not in a git repo — fall back to cwd
 47→		return join(resolve(process.cwd()), ".claude");
 48→	}
 49→}
 50→
 51→export function getClaudeSettingsPath(): string {
 52→	return join(findClaudeDir(), "settings.json");
 53→}
 54→
 55→export function readClaudeSettings(): ClaudeSettings {
 56→	const path = getClaudeSettingsPath();
 57→	if (!existsSync(path)) return {};
 58→	const content = readFileSync(path, "utf-8");
 59→	return JSON.parse(content) as ClaudeSettings;
 60→}
 61→
 62→export function writeClaudeSettings(settings: ClaudeSettings): void {
 63→	const path = getClaudeSettingsPath();
 64→	mkdirSync(dirname(path), { recursive: true });
 65→	writeFileSync(path, `${JSON.stringify(settings, null, 2)}\n`);
 66→}
 67→
 68→export function isHookEnabled(): boolean {
 69→	const settings = readClaudeSettings();
 70→	const entries = settings.hooks?.SessionEnd;
 71→	if (!Array.isArray(entries)) return false;
 72→	return entries.some((entry) =>
 73→		entry.hooks?.some((h) => h.command === HOOK_COMMAND),
 74→	);
 75→}
 76→
 77→export function addHook(): void {
 78→	const settings = readClaudeSettings();
 79→	if (!settings.hooks) {
 80→		settings.hooks = {};
 81→	}
 82→	if (!Array.isArray(settings.hooks.SessionEnd)) {
 83→		settings.hooks.SessionEnd = [];
 84→	}
 85→
 86→	const alreadyExists = settings.hooks.SessionEnd.some((entry) =>
 87→		entry.hooks?.some((h) => h.command === HOOK_COMMAND),
 88→	);
 89→	if (alreadyExists) return;
 90→
 91→	settings.hooks.SessionEnd.push({
 92→		matcher: "",
 93→		hooks: [{ type: "command", command: HOOK_COMMAND, async: true }],
 94→	});
 95→
 96→	writeClaudeSettings(settings);
 97→}
 98→
 99→export function removeHook(): void {
100→	const settings = readClaudeSettings();
101→	const hooks = settings.hooks;
102→	const entries = hooks?.SessionEnd;
103→	if (!hooks || !Array.isArray(entries)) return;
104→
105→	hooks.SessionEnd = entries.filter(
106→		(entry) => !entry.hooks?.some((h) => h.command === HOOK_COMMAND),
107→	);
108→
109→	if (hooks.SessionEnd.length === 0) {
110→		delete hooks.SessionEnd;
111→	}
112→	if (Object.keys(hooks).length === 0) {
113→		delete settings.hooks;
114→	}
115→
116→	writeClaudeSettings(settings);
117→}
